init_eqs:
n = 0; loop (10000,gmegabuf(n) = 0; megabuf(n) = 0; n+=1);
num_res = 100; MINBPM = 90; MAXBPM = 200;
sax1 = rand(5); sax2 = rand(5); sax3 = rand(5);
r1 = rand(1); r2 = rand(1); j0=j1=j2=0; r4 = rand(2)-1;
index = 1; nstab = int(rand(10))+4;;
r1_ = rand(1); r2_=rand(1);
BMP=100; certain = 2; jrel=0; jtime = 0; smov=0;

frame_eqs:
dt = 1/fps;
dec_s = 1-.015*30/fps; dec_m = 1-0.1*30/fps; dec_f = 0.7;
vol = vol*0.3 + 0.7*(bass_att + mid_att + treb_att)/3; vol_ = vol_*dec_f + (1-dec_f)*vol;
avg = avg*dec_m + (1-dec_m)*vol;

is_beat = above(vol, 1.75*peak) * above (time, t0+.25);
t0 = if(is_beat,time,t0);
peak = if (is_beat, vol, peak*dec_m);
index = (index + is_beat) %32;
index2 = (index2 + is_beat*bnot(index))%16;

//biquad lowpass
fg = BPM/60; Q=1.8; omega = 6.283*min(0.5,fg/fps); tcos = cos (omega); alpha = sin(omega)/(2*Q);
b0=(1-tcos)/2; b1=1-tcos; b2=(1-tcos)/2; a0=1+alpha; a1=-2*tcos; a2=1-alpha;
b0a0=b0/a0; b1a0=b1/a0; b2a0=b2/a0; a1a0=a1/a0; a2a0=a2/a0;
X = vol; LastOut= b0a0*X + b1a0*in1 + b2a0*in2 - a1a0*ou1 - a2a0*ou2;
in2 =in1; in1 =X; ou2 =ou1;  ou1 =LastOut; X =LastOut;
BiVol=X;

maxind = 0; qavg = 0.1; i=0;
Excite = (vol-vol_);
loop (num_res,
n = i*8;
Freq  = (i/(num_res-1)+minbpm/(maxbpm-minbpm))*(maxbpm-minbpm)/60;
Feder = sqr(Freq*6.2832);
megabuf (n+4) = megabuf(n+1); megabuf (n+1) *= 1-0.25*dt;
EC_Steps = int (10*Freq*dt)+1;
loop (EC_Steps, // Euler-Cauchy steps
Kraft = Excite - Feder*megabuf(n + 2) ;
megabuf (n+1) += Kraft        * dt/EC_Steps;
megabuf (n+2) += megabuf(n+1) * dt/EC_Steps;  );
beatcos = megabuf(n+1);  beatsin = megabuf(n+2)*Freq*6.2832;
quad = sqrt (pow(beatsin,2) + pow(beatcos,2));
megabuf (n+3) = megabuf(n+3) *dec_m +  quad* (1-dec_m);
if (megabuf(n+3) > megabuf (maxind*8+3), maxind =i,0);
qavg = qavg+pow (megabuf(n+3),2);
i += 1;);

qavg = sqrt (qavg/num_res);
qdev = 0; i =0; loop (num_res, qdev += pow(megabuf(i+3)-qavg,2); i += 8; );
qdev = sqrt (qdev/num_res);
BPM =   (maxind/(num_res-1)+minbpm/(maxbpm-minbpm))*(maxbpm-minbpm);

m1 = maxind*8;
certain = certain * dec_m + (1-dec_m) * megabuf(m1+3)/qavg;
dbl_beat = megabuf(m1+1) * megabuf (m1+4) < 0;
sgl_beat = dbl_beat * (megabuf (m1+4) < 0);
pulse = (megabuf(m1+2) > 0)-0.5;
bcount += dbl_beat;is_rbeat  = dbl_beat && (bcount%2==0);bcount2 += is_rbeat;
trel1 += BPM/60*dt;

trig2 = is_beat && (index%12==0);
r1 = if (trig2,(rand(17)-1)*0.1,r1); r1_ += min(0.1,max(-0.1, r1-r1_))*dt*5;
r2 = if (trig2,rand(1)-0.3,r2);      r2_ += min(0.1,max(-0.1, r2-r2_))*dt*5;
r3 = if (trig2,vol*0.6*min(1,max(-1,sin(rand(24)))),r3); r30 = r30*dec_m + (1-dec_m)*r3; r3_ += r30*dt;
r4 = if (trig2, (rand(2)-1)*rand(2), r4); r4_ +=r4*dt;

//Comp PLANE
ax=-r1_; ay = r3_; az = r2_+j0*jrel;
c1 = cos(ax); c2 = cos(ay); c3 = cos(az); s1 = sin(ax); s2 = sin(ay); s3 = sin(az);
q20 = c2*c3;            q21 = c2*s3;            q22= -s2;
q23 = s1*s2*c3 - c1*s3; q24 = s1*s2*s3 + c1*c3; q25 = s1*c2;
q26 = c1*s2*c3 + s1*s3; q27 = c1*s2*s3 - s1*c3; q28 = c1*c2;
q17 = s2*q24*2; q18 = c2*q24*2; //for Profile

//persp. center
jscale = min (1.2, pow(125/(1+BPM),2));
if (dbl_beat, (j0=rand(2)-1)*jscale; j1=0; j2=((rand(6)-2))*jscale,0);
jrelv = (certain>6.5-min(avg,2)-jrelv+jtime/8 + 2*(BPM > 160)) ;
jrel  = if(dbl_beat, jrelv,jrel);
jtime = max(0,if (jrel, jtime + dt, jtime-dt));
q7 = sin(r3_/7+r1_*4); q8 = 1.25+sin(r3_*.77+r1_)*.5*c1; //pfusch
q9 = 10-j2*jrel; //z pos

trig1 = is_beat && (index%16==0);
sax1 = if (trig1, rand(12), sax1);
sax2 = if (trig1, rand(12), sax2);
sax3 = if (trig1, rand(6), sax3);
nstab = if (trig1 && (index2%2==0), int(rand(10)*rand(10)+4), nstab);

//delay chain
n = 100; loop (100, gmegabuf(n)=gmegabuf(n-1); n-=1); gmegabuf(0) = vol;

//resampled delay chain starts at 500.
n = 0; num = 60/BPM/dt; //Num delay bins auf nstab abbilden
sca =   num/nstab;
loop (nstab,
m1 = floor (sca*n); fra = sca*n-m1;
gmegabuf(500+n) = (1-fra)*gmegabuf(m1) + fra*gmegabuf(m1+1);
n +=1);

//2nd resampled delay chain starts at 5000.
n = 0; num = 60/BPM/dt; //Num delay bins auf nstab abbilden
sca =   num/200;
dec = 0.5;
loop (200,
m1 = floor (sca*n); fra = sca*n-m1;
gmegabuf(5000+n) = dec*gmegabuf(5000+n) + (1-dec)*1.5*sqrt((1-fra)*gmegabuf(m1) + fra*gmegabuf(m1+1));
n +=1);

//Now to stabs
slen = 2; sdia = 0.13;
n = 100;
loop (100,
megabuf(5000+n)=megabuf(5000+n-1);
megabuf(6000+n)=megabuf(6000+n-1);
megabuf(7000+n)=megabuf(7000+n-1);
megabuf(8000+n)=megabuf(8000+n-1);
n-=1);;
megabuf (5000) = megabuf(5000)*dec_f + (1-dec_f)*sax1;
megabuf (6000) = megabuf(6000)*dec_f + (1-dec_f)*sax2;
megabuf (7000) = megabuf(7000)*dec_f + (1-dec_f)*sax3;
megabuf (8000) = BiVol;

p = 1;
loop (2,
stab = 0;
loop (nstab,
xang = megabuf(5000+25*stab/nstab); yang = megabuf(6000+30*stab/nstab); zang = 0;
dia = megabuf(7000+20*stab/nstab) ;
c1 = cos(xang); c2 = cos(yang); c3 = cos(zang);
s1 = sin(xang); s2 = sin(yang); s3 = sin(zang);
ox = 0; oy = 0;  if (p==1, oz = -slen, oz=slen); ;
mx = ox*c3 - oy*s3; my = ox*s3 + oy*c3;    ox = mx; oy = my;
mx = ox*c2 + oz*s2; mz = - ox*s2 + oz*c2;  ox = mx; oz = mz;
my = oy*c1 - oz*s1; mz = oy*s1 + oz*c1;    oy = my; oz = mz;
x0 = ox+dia/2; y0 = oy; z0 = oz+slen+.1;
xang = 0; yang = 0; zang = 6.283 * stab/nstab+r4_; //alle Stebe anordnen
ox = x0; oy=y0;  oz=z0;
c1 = cos(xang); c2 = cos(yang); c3 = cos(zang);
s1 = sin(xang); s2 = sin(yang); s3 = sin(zang);
mx = ox*c3 - oy*s3; my = ox*s3 + oy*c3;    ox = mx; oy = my;
mx = ox*c2 + oz*s2; mz = - ox*s2 + oz*c2;  ox = mx; oz = mz;
my = oy*c1 - oz*s1; mz = oy*s1 + oz*c1;    oy = my; oz = mz;
oz += max(0,certain-2.5)/6*BiVol/(0.2+sqrt(ox*ox+oy*oy));

base = p*1000+4*stab;
gmegabuf (base)=ox;
gmegabuf (base+1)=oy;
gmegabuf (base+2)=oz;
stab += 1);
p += 1);

q1 = megabuf(maxind*8+1)/megabuf(maxind*8+3);
q2 = index2%2;
q3 = min(vol_,3)*2;
q11 = trel1;

reg10 = nstab;
reg11 = sdia; //Dicke Stab
q31 = aspectx;
q32 = aspecty;
q19 = min(3,1/pow(avg+0.1,0.7))*1.7;

//shape 4
r0 = 0.38-0.4*gmegabuf(5000);
x0 = 0;
y0 = 0;
z0 = 2*cos(tht)*-r0+0.5;
Nenner = q9 + q28*x0 + q26*y0 - q27*z0;
x = (q7 + q22*x0 + q20*y0 -q21*z0)/Nenner + 0.5;
y = -(q8 + q25*x0 + q23*y0 -q24*z0 )/Nenner*q32 +0.5;
q15 = x-0.5; q16 = y-0.5;

//for wave4:
reg15 = z0;
reg04 =  is_beat;
z0_alt = z0;

z0 = -z0;
Nenner = q9 + q28*x0 + q26*y0 - q27*z0;
x = (q7 + q22*x0 + q20*y0 -q21*z0)/Nenner + 0.5;
y = -(q8 + q25*x0 + q23*y0 -q24*z0 )/Nenner*q32 +0.5;
q5 = x-0.5; q6 = y-0.5;

monitor = reg04;

shape_2_per_frame:
xs = xs*(1 - 2*above(xm,0.99) - 2*below(xm,0.01));
ys = ys*(1 - 2*above(ym,0.99) - 2*below(ym,0.01));

xm = xm + 0.03*xs*(sin(time*0.35)*0.5 + 0.5*cos(time*0.87));
ym = ym + 0.03*ys*(sin(time*0.92)*0.3 + 0.7*cos(time*0.26));

x = xm;
y = ym;

r = 0.5 + 0.5*sin(time*0.25);
g = 0.5 + abs(r)*sin(time*0.5);
b = 0.5 + abs(g)*sin(time);
r2 = r; g2 = g; b2 = b;
rad = 1.6*(bass_att + mid_att + treb_att)/3;
